def swap_cyc(arr, ans, i, j):
    cswap(arr, ans, i, j)
    curr = i
    while arr[-arr[curr]] > 0:
        cswap(arr, ans, curr, -arr[curr])
    curr = -arr[curr]
    while arr[-arr[curr]] > 0:
        cswap(arr, ans, curr, -arr[curr])
