    if isinstance(input_data, str):
        lines = input_data.strip().split('\n')
        n = int(lines[0])
        arr = [0] + list(map(int, lines[1].split()))
    else:
        return
    vis = [False] * (n + 1)
    ans = []
    p = -1
    for x in range(1, n + 1):
        if vis[x]:
            continue
        if arr[x] == x:
            continue
        curr = x
        while True:
            vis[curr] = True
            curr = arr[curr]
            if curr == x:
                break
        if p == -1:
            p = x
        else:
            swap_cyc(arr, ans, p, x)
            p = -1
    if p != -1:
        can = False
        for x in range(1, n + 1):
            if arr[x] == x:
                swap_cyc(arr, ans, p, x)
                can = True
                break
        if not can:
            t1 = arr[p]
            t2 = arr[arr[p]]
            cswap(arr, ans, p, t1)
            swap_cyc(arr, ans, t1, t2)
    result = [str(len(ans))]
    for op in ans:
        result.append(f'{op[0]} {op[1]}')
    return '\n'.join(result)

